(window.webpackJsonp=window.webpackJsonp||[]).push([[191],{818:function(n,t){n.exports="\x3c!-- \ntitle: 08-Nginx+Tomcat\nsort: \n--\x3e \n\n> 配置文件列表\n>\n> `/etc/nginx/nginx.cong`\n>\n> `/opt/`\n\n## Nginx配置文件\n\n```nginx\n# /etc/nginx/sites-enable/default\n\nserver {\n\tlisten 80;\n    server_name localhost;\n\n\tlocation / {\n\t\troot /var/www/html;\n\t\tindex index.html index.htm index.nginx-debian.html;\n\t}\n}\n\ninclude\t<someconfig>\n```\n\n### 反向代理\n\n```nginx\nlocation /test {\n\t# 反向代理\n\tproxy_pass http://group1/;\n}\n```\n\n### 负载均衡\n\n```nginx\n# 负载均衡 权重\nupstream group1{\n   \tserver 192.168.0.1:80 weight=2;\n    server 192.168.0.1:8080 weight=1;\n}\n\nserver{\n    location /test/ {\n        # 随机重定向到两个网页\n\t\tproxy_pass http://group1/;\n  }\n}\n```\n\n"}}]);